local function kfLog(m) local s = "[Keyforge Auth] " .. tostring(m) pcall(function() if type(print) == "function" then print(s) end end) pcall(function() if type(warn) == "function" then warn(s) end end) end kfLog("loader started") local function kfFetch(u) local headers = { ["X-KeyForge-Executor"] = "1" } local function pickResult(res) if type(res) ~= "table" then return nil end local status = res.StatusCode or res.status_code or 0 local body = res.Body or res.body if type(body) ~= "string" then body = body and tostring(body) or "" end if body ~= "" then if status == 200 then return body end if body:find("KeyForge", 1, true) or body:find("Keyforge", 1, true) then return body end local hint = body:match("^%-%- KeyForge: (.+)") return nil, hint or body end if status ~= 0 and status ~= 200 then return nil, "request failed (HTTP " .. tostring(status) .. ")" end return nil end local httpRequest = (syn and syn.request) or (http and http.request) or (fluxus and fluxus.request) or request or http_request if type(httpRequest) == "function" then local ok, res = pcall(function() return httpRequest({ Url = u, Method = "GET", Headers = headers }) end) if ok then local body, err = pickResult(res) if body then return body end if err then return nil, err end end end local HttpService = game:GetService("HttpService") if HttpService.RequestAsync then local ok, res = pcall(function() return HttpService:RequestAsync({ Url = u, Method = "GET", Headers = headers }) end) if ok then local body, err = pickResult(res) if body then return body end if err then return nil, err end end end local ok, body = pcall(function() if type(httpget) == "function" then return httpget(u) end if game.HttpGetAsync then return game:HttpGetAsync(u) end return game:HttpGet(u, true) end) if ok and type(body) == "string" and body ~= "" then return body end if not ok and type(body) == "string" and body ~= "" then return nil, body end return nil, "failed to fetch loader" end kfLog("fetching bootstrap") local body, kfErr = kfFetch("https://www.keyforge.win/v1/load/cmrbwmg1j00000ahs7gzg1dsh?e=1&script=cmrdyvgcc000004lbq2ttf5q4&lsig=IHzcCTZFrMcVjwA7H6MLKSNJw-nqsyNPjx-pWHKALjQ&key=" .. _G.script_key.."&_cb="..tostring(os.clock()).."-"..tostring(math.random(1,1e9))) if not body then local msg = kfErr or "failed to fetch loader" if type(error) == "function" then error("[Keyforge Auth] " .. msg, 0) end if type(print) == "function" then print("[Keyforge Auth] " .. msg) end while true do end end kfLog("bootstrap fetched (" .. tostring(#body) .. " bytes)") kfLog("running bootstrap") local function kfTry(fn) if type(fn)~="function" then return end local ok,res=pcall(fn,"return 1") if ok then return fn end local m=tostring(res or "") if not(m:find("RobloxScript",1,true) or m:find("not available",1,true)) then return fn end end local function kfPick(t) if type(t)~="table" then return end return kfTry(t.__cload) or kfTry(t.loadstring) or kfTry(t.load) end local _kf_ls=(type(getgenv)=="function" and kfPick(getgenv())) or (type(Opiumware)=="table" and kfPick(Opiumware)) or (function() if type(getrenv)~="function" then return end local ok,re=pcall(getrenv) if ok then return kfPick(re) end end)() or kfTry(loadstring) or kfTry(load) assert(type(_kf_ls) == "function", "[Keyforge Auth] no loader function") local fn, err = _kf_ls(body) if type(fn) ~= "function" then error("load failed: " .. tostring(err or fn or "not a function"), 0) end local _kf_ok, _kf_runerr = pcall(fn) if not _kf_ok then error(tostring(_kf_runerr), 0) end return _kf_runerr
